def validate(args, output):
    n = args[0]
    if not isinstance(output, str) or len(output) != n:
        return False
    from collections import Counter
    for c, cnt in Counter(output).items():
        if not c.islower():
            return False
        if cnt % 2 == 0:
            return False
    return True

