function validate(args, output) {
    const n = args[0];
    if (typeof output !== 'string' || output.length !== n) return false;
    const freq = {};
    for (const c of output) {
        if (c < 'a' || c > 'z') return false;
        freq[c] = (freq[c] || 0) + 1;
    }
    return Object.values(freq).every(cnt => cnt % 2 === 1);
}

